// deepCopyItem creates a deep copy of a map[string]interface{} to prevent modification of the original item by JavaScript scripts.
func deepCopyItem(item map[string]interface{}) (map[string]interface{}, error) {
	data, err := json.Marshal(item)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal item for deep copy: %w", err)
	}
	var copy map[string]interface{}
	err = json.Unmarshal(data, &copy)
	if err != nil {
		return nil, fmt.Errorf("failed to unmarshal item for deep copy: %w", err)
	}
	return copy, nil
}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security improvements:
// 1. Deep copies items before injection to prevent script from modifying original data.
// 2. Adds execution timeout (5 seconds) to prevent infinite loops/long-running scripts.
// 3. Compiles script once to catch syntax errors early and improve performance.
// 4. Uses fresh VM per item to isolate execution state between items.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Compile the condition script once to catch syntax errors early
	vmCompile := otto.New()
	script, err := vmCompile.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("failed to compile condition script: %w", err)
	}

	var result []map[string]interface{}

	for _, item := range items {
		// Create a deep copy of the item to prevent script from modifying the original
		itemCopy, err := deepCopyItem(item)
		if err != nil {
			return nil, fmt.Errorf("failed to deep copy item: %w", err)
		}

		// Create a fresh VM for each item to isolate execution state
		vm := otto.New()

		// Set up execution timeout (5 seconds) to prevent infinite loops or long-running scripts
		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		// Start goroutine to interrupt VM if timeout is reached
		go func() {
			<-ctx.Done()
			// Send interrupt signal to the VM (otto's current API uses a channel for interrupts)
			select {
			case vm.Interrupt <- func() {}:
			default:
				// Ignore if channel is full or VM is no longer running
			}
		}()

		// Inject the copied item as a global variable named 'item'
		err = vm.Set("item", itemCopy)
		if err != nil {
			return nil, fmt.Errorf("failed to inject item into VM: %w", err)
		}

		// Run the pre-compiled condition script
		value, err := vm.Run(script)
		if err != nil {
			return nil, fmt.Errorf("failed to run condition script for item: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
		}

		if boolResult {
			// Append the original item (not the copy) to the result
			result = append(result, item)
		}
	}

	return result, nil
}

