package main

import (
	"fmt"
	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Original input items are not modified even if the script alters the 'item' variable.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Reuse a single VM instance for all items to improve performance
	vm := otto.New()

	for _, item := range items {
		// Create a deep copy of the item to isolate script modifications from original data
		copiedItem, err := deepCopy(item)
		if err != nil {
			return nil, err
		}

		// Inject the copied item as the global 'item' variable
		err = vm.Set("item", copiedItem)
		if err != nil {
			return nil, err
		}

		// Evaluate the condition script
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness rules
		isIncluded, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if isIncluded {
			// Append the original item (not the copy) to preserve original state
			result = append(result, item)
		}
	}

	return result, nil
}

// deepCopy creates a deep copy of a value, handling nested maps, slices, and basic Go types.
// Returns an error if encountering unsupported types (e.g., structs, channels).
func deepCopy(v interface{}) (interface{}, error) {
	switch val := v.(type) {
	case map[string]interface{}:
		copy := make(map[string]interface{}, len(val))
		for key, value := range val {
			copiedValue, err := deepCopy(value)
			if err != nil {
				return nil, err
			}
			copy[key] = copiedValue
		}
		return copy, nil
	case []interface{}:
		copy := make([]interface{}, len(val))
		for i, value := range val {
			copiedValue, err := deepCopy(value)
			if err != nil {
				return nil, err
			}
			copy[i] = copiedValue
		}
		return copy, nil
	case string, int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64, bool, nil:
		// Basic value types can be copied directly
		return val, nil
	default:
		return nil, fmt.Errorf("unsupported type for deep copy: %T", val)
	}
}

