		}

		// Create a new isolated VM for each item to prevent cross-item state leakage
		vm := otto.New()

		// Inject the copied item as a global variable named 'item'
		err = vm.Set("item", copiedItem)
		if err != nil {
			return nil, fmt.Errorf("failed to set copied item in VM: %w", err)
