		copiedItem := deepCopyMap(item)

		// Inject copied item as global 'item' variable
		err := vm.Set("item", copiedItem)
		if err != nil {
			return nil, err
		}

		// Execute pre-compiled script
		value, err := vm.Run(script)
		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		// Append original (unmodified) item to result if condition passes
		if boolResult {
			result = append(result, item)
		}
	}

